“//+------------------------------------------------------------------+
//|                                                ZigZag EA.mq4     |
//|                   从ZigZag指标转换的EA由ChatGPT提供               |
//+------------------------------------------------------------------+
#property strict

// 输入参数
input int 输入深度 = 12;           // 深度
input int 输入偏差 = 5;            // 偏差
input int 输入回溯 = 3;            // 回溯
input double 手数 = 0.1;           // 订单手数
input double 跟踪止损点 = 200;     // 跟踪止损的点差

double ZigZag缓冲区[];
double 高点缓冲区[];
double 低点缓冲区[];

bool 是多单 = false;
bool 是空单 = false;
double 当前止损价 = 0.0;

int OnInit()
{
   // 初始化缓冲区
   ArraySetAsSeries(ZigZag缓冲区, true);
   ArraySetAsSeries(高点缓冲区, true);
   ArraySetAsSeries(低点缓冲区, true);
   return(INIT_SUCCEEDED);
}

void OnTick()
{
   int 限制 = iBars(NULL, 0) - 输入深度;
   double 最后低点 = 0, 最后高点 = 0;
   int 最后低点位置 = -1, 最后高点位置 = -1;

   // 遍历K线，寻找最新的ZigZag高点和低点
   for (int i = 限制; i >= 0; i--)
   {
      double 低价 = iLow(NULL, 0, i);
      double 高价 = iHigh(NULL, 0, i);

      if (是否为ZigZag低点(i, 低价))
      {
         最后低点 = 低价;
         最后低点位置 = i;
      }

      if (是否为ZigZag高点(i, 高价))
      {
         最后高点 = 高价;
         最后高点位置 = i;
      }

      // 只需要最近的高点和低点
      if (最后低点位置 != -1 && 最后高点位置 != -1) break;
   }

   // 交易逻辑：判断当前K线是否是高点或低点并开仓
   if (最后高点位置 == 0)  // 当前K线是高点，开空单
   {
      if (!是空单) // 如果没有空单
      {
         平仓所有仓位();
         开空单(最后高点);
      }
   }
   else if (最后低点位置 == 0)  // 当前K线是低点，开多单
   {
      if (!是多单) // 如果没有多单
      {
         平仓所有仓位();
         开多单(最后低点);
      }
   }

   // 跟踪止损逻辑
   if (是多单)
   {
      double 新止损价 = Bid - 跟踪止损点 * Point;
      if (新止损价 > 当前止损价)
      {
         修改止损(OP_BUY, 新止损价);
         当前止损价 = 新止损价;
      }
   }
   else if (是空单)
   {
      double 新止损价 = Ask + 跟踪止损点 * Point;
      if (新止损价 < 当前止损价)
      {
         修改止损(OP_SELL, 新止损价);
         当前止损价 = 新止损价;
      }
   }
}

// 辅助函数：判断是否为ZigZag低点
bool 是否为ZigZag低点(int 索引, double 低价)
{
   bool 是低点 = true;
   for (int i = 1; i <= 输入深度; i++)
   {
      if (低价 >= iLow(NULL, 0, 索引 - i) || 低价 >= iLow(NULL, 0, 索引 + i))
      {
         是低点 = false;
         break;
      }
   }
   return 是低点 && (iHigh(NULL, 0, 索引) - 低价) >= 输入偏差 * Point;
}

// 辅助函数：判断是否为ZigZag高点
bool 是否为ZigZag高点(int 索引, double 高价)
{
   bool 是高点 = true;
   for (int i = 1; i <= 输入深度; i++)
   {
      if (高价 <= iHigh(NULL, 0, 索引 - i) || 高价 <= iHigh(NULL, 0, 索引 + i))
      {
         是高点 = false;
         break;
      }
   }
   return 是高点 && (高价 - iLow(NULL, 0, 索引)) >= 输入偏差 * Point;
}

// 函数：平掉所有仓位
void 平仓所有仓位()
{
   for (int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if (OrderSelect(i, SELECT_BY_POS) && OrderSymbol() == Symbol())
      {
         if (OrderType() == OP_BUY)
         {
            OrderClose(OrderTicket(), OrderLots(), Bid, 3, clrRed);
            是多单 = false;
            当前止损价 = 0.0;
         }
         else if (OrderType() == OP_SELL)
         {
            OrderClose(OrderTicket(), OrderLots(), Ask, 3, clrGreen);
            是空单 = false;
            当前止损价 = 0.0;
         }
      }
   }
}

// 函数：开多单
void 开多单(double 价格)
{
   double 初始止损 = 价格 - 跟踪止损点 * Point;
   if (OrderSend(Symbol(), OP_BUY, 手数, Ask, 3, 初始止损, 0, "ZigZag Buy", 0, 0, clrGreen) > 0)
   {
      是多单 = true;
      是空单 = false;
      当前止损价 = 初始止损;
   }
}

// 函数：开空单
void 开空单(double 价格)
{
   double 初始止损 = 价格 + 跟踪止损点 * Point;
   if (OrderSend(Symbol(), OP_SELL, 手数, Bid, 3, 初始止损, 0, "ZigZag Sell", 0, 0, clrRed) > 0)
   {
      是空单 = true;
      是多单 = false;
      当前止损价 = 初始止损;
   }
}

// 函数：修改止损
void 修改止损(int 订单类型, double 新止损价)
{
   for (int i = OrdersTotal() - 1; i >= 0; i--)
   {
      if (OrderSelect(i, SELECT_BY_POS) && OrderSymbol() == Symbol() && OrderType() == 订单类型)
      {
         OrderModify(OrderTicket(), OrderOpenPrice(), 新止损价, OrderTakeProfit(), OrderExpiration(), clrYellow);
      }
   }
}
”：这个mt4的EA程序逻辑帮忙修正下，高点就开空仓，持仓直到调整触发跟踪止损的止损位，等待下一个高点或低点出现，出现低点开多仓，持仓到触发止损。

要调整你的EA程序，使其符合你的描述的交易逻辑，需要确保：

1. 当产生一个新的高点时，如果没有当前的空仓，则关闭任何现有的多仓并同时开一个新的空仓。
2. 当产生一个新的低点时，如果没有当前的多仓，则关闭任何现有的空仓并同时开一个新的多仓。
3. 当价格反转至触发跟踪止损时关闭仓位直到新的信号产生。

以下是经过调整后的 EA 程序：

