    int i, 限制, 计数Z, 寻找类型 = 0;
    int 回溯, 位置, 上次高点位置 = 0, 上次低点位置 = 0;
    double 极值;
    double 当前低点 = 0.0, 当前高点 = 0.0, 上次高点 = 0.0, 上次低点 = 0.0;

    //--- 检查历史数据和输入
    if (总条数 < 输入深度 || 输入回溯步数 >= 输入深度)
        return(0);

    //--- 首次计算
    if (上次计算的 == 0)
        限制 = 初始化所有参数();
    else 
    {
        //--- 在深度为ExtLevel或100根柱线中找到第一个极值
        i = 计数Z = 0;
        while (计数Z < 极值等级 && i < 100)
        {
            if (极值缓冲区[i] != 0.0)
                计数Z++;
            i++;
        }

        //--- 若没有找到极值，则重新计算所有内容
        if (计数Z == 0)
            限制 = 初始化所有参数();
        else
        {
            //--- 设置开始位置到找到的极值位置
            限制 = i - 1;

            //--- 判断极值类型
            if (低点缓冲区[i] != 0.0)
            {
                //--- 低点极值
                当前低点 = 低点缓冲区[i];
                //--- 寻找下一个高点极值
                寻找类型 = 1;
            }
            else
            {
                //--- 高点极值
                当前高点 = 高点缓冲区[i];
                //--- 寻找下一个低点极值
                寻找类型 = -1;
            }

            //--- 清除其余数据
            for (i = 限制 - 1; i >= 0; i--)  
            {
                极值缓冲区[i] = 0.0;  
                低点缓冲区[i] = 0.0;
                高点缓冲区[i] = 0.0;
            }
        }
    }

    //--- 主循环      
    for (i = 限制; i >= 0; i--)
    {
        //--- 在深度范围内找到最低的最低价
        极值 = 最低价[iLowest(NULL, 0, MODE_LOW, 输入深度, i)];

        //--- 这个最低价已经被之前找到
        if (极值 == 上次低点)
            极值 = 0.0;
        else 
        { 
            //--- 新的最低点
            上次低点 = 极值; 
            //--- 如果当前低点过高，丢弃极值
            if (最低价[i] - 极值 > 输入偏差 * Point)
                极值 = 0.0;
            else
            {
                //--- 清除回溯范围内的前一个极值
                for (回溯 = 1; 回溯 <= 输入回溯步数; 回溯++)
                {
                    位置 = i + 回溯;
                    if (低点缓冲区[位置] != 0 && 低点缓冲区[位置] > 极值)
                        低点缓冲区[位置] = 0.0; 
                }
            }
        } 

        //--- 当前极值是最低价
        if (最低价[i] == 极值)
            低点缓冲区[i] = 极值;
        else
            低点缓冲区[i] = 0.0;

        //--- 在深度范围内找到最高的最高价
        极值 = 最高价[iHighest(NULL, 0, MODE_HIGH, 输入深度, i)];

        //--- 这个最高价已经被之前找到
        if (极值 == 上次高点)
            极值 = 0.0;
        else 
        {
            //--- 新的最高点
            上次高点 = 极值;
            //--- 如果当前高点过低，丢弃极值
            if (极值 - 最高价[i] > 输入偏差 * Point)
                极值 = 0.0;
            else
            {
                //--- 清除回溯范围内的前一个极值
                for (回溯 = 1; 回溯 <= 输入回溯步数; 回溯++)
                {
                    位置 = i + 回溯;
                    if (高点缓冲区[位置] != 0 && 高点缓冲区[位置] < 极值)
                        高点缓冲区[位置] = 0.0; 
                } 
            }
        }

        //--- 当前极值是最高价
        if (最高价[i] == 极值)
            高点缓冲区[i] = 极值;
        else
            高点缓冲区[i] = 0.0;
    }

    //--- 最终裁剪 
    if (寻找类型 == 0)
    {
        上次低点 = 0.0;
        上次高点 = 0.0;  
    }
    else
    {
        上次低点 = 当前低点;
        上次高点 = 当前高点;
    }

    for (i = 限制; i >= 0; i--)
    {
        switch (寻找类型)
        {
            case 0: // 寻找峰或谷
                if (上次低点 == 0.0 && 上次高点 == 0.0)
                {
                    if (高点缓冲区[i] != 0.0)
                    {
                        上次高点 = 最高价[i];
                        上次高点位置 = i;
                        寻找类型 = -1;
                        极值缓冲区[i] = 上次高点;
                    }

                    if (低点缓冲区[i] != 0.0)
                    {
                        上次低点 = 最低价[i];
                        上次低点位置 = i;
                        寻找类型 = 1;
                        极值缓冲区[i] = 上次低点;
                    }
                }
                break;

            case 1: // 寻找峰
                if (低点缓冲区[i] != 0.0 && 低点缓冲区[i] < 上次低点 && 高点缓冲区[i] == 0.0)
                {
                    极值缓冲区[上次低点位置] = 0.0;
                    上次低点位置 = i;
                    上次低点 = 低点缓冲区[i];
                    极值缓冲区[i] = 上次低点;
                }

                if (高点缓冲区[i] != 0.0 && 低点缓冲区[i] == 0.0)
                {
                    上次高点 = 高点缓冲区[i];
                    上次高点位置 = i;
                    极值缓冲区[i] = 上次高点;
                    寻找类型 = -1;
                }   
                break;               

            case -1: // 寻找谷
                if (高点缓冲区[i] != 0.0 && 高点缓冲区[i] > 上次高点 && 低点缓冲区[i] == 0.0)
                {
                    极值缓冲区[上次高点位置] = 0.0;
                    上次高点位置 = i;
                    上次高点 = 高点缓冲区[i];
                    极值缓冲区[i] = 上次高点;
                }

                if (低点缓冲区[i] != 0.0 && 高点缓冲区[i] == 0.0)
                {
                    上次低点 = 低点缓冲区[i];
                    上次低点位置 = i;
                    极值缓冲区[i] = 上次低点;
                    寻找类型 = 1;
                }   
                break;               
        }
    }

    //--- 完成
    return(总条数);
}

